// ── Selec EM2M Register Map (0-based from 3999) ──
// Index 0  = Voltage L1-N   (÷10 → V)
// Index 1  = Voltage L2-N   (÷10 → V)
// Index 2  = Voltage L3-N   (÷10 → V)
// Index 3  = Current L1     (÷10 → A)
// Index 4  = Current L2     (÷10 → A)
// Index 5  = Current L3     (÷10 → A)
// Index 6  = Active Power   (÷10 → kW)
// Index 7  = Power Factor   (÷1000, signed INT)
// Index 8  = Frequency      (÷10 → Hz)
// Index 9/10 = Energy kWh   (DWORD Hi/Lo ÷10)

const r = msg.payload.data;
if (!r || r.length < 11) {
    node.warn('Not enough registers: ' + (r ? r.length : 0));
    return null;
}

// Helper: WORD to signed INT (two's complement 16-bit)
function toInt16(w) {
    return w > 32767 ? w - 65536 : w;
}

// Helper: Two WORDs to DWORD
function toDword(hi, lo) {
    return ((hi & 0xFFFF) << 16) | (lo & 0xFFFF);
}

const data = {
    ts:          Math.floor(Date.now() / 1000),
    meter_id:    'meter01',
    location:    'building-a',

    // Electrical measurements
    V_L1:        parseFloat((r[0] / 10).toFixed(1)),
    V_L2:        parseFloat((r[1] / 10).toFixed(1)),
    V_L3:        parseFloat((r[2] / 10).toFixed(1)),
    I_L1:        parseFloat((r[3] / 10).toFixed(2)),
    I_L2:        parseFloat((r[4] / 10).toFixed(2)),
    I_L3:        parseFloat((r[5] / 10).toFixed(2)),
    kW:          parseFloat((r[6] / 10).toFixed(3)),
    PF:          parseFloat((toInt16(r[7]) / 1000).toFixed(3)),
    Hz:          parseFloat((r[8] / 10).toFixed(1)),
    kWh:         parseFloat((toDword(r[9], r[10]) / 10).toFixed(1)),

    // Derived values
    kVA:         parseFloat(((r[6] / 10) / Math.max(Math.abs(toInt16(r[7]) / 1000), 0.01)).toFixed(3)),
    CO2_kg:      parseFloat(((r[9] * 65536 + r[10]) / 10 * 0.5919).toFixed(2)),
};

// Alarm flag: peak demand > 15 kW
data.alarm_peak = data.kW > 15.0;

node.status({ fill: data.alarm_peak ? 'red' : 'green',
              shape: 'dot',
              text: data.kW + ' kW | PF ' + data.PF });

msg.payload = data;
msg.topic   = 'factory/' + data.location + '/' + data.meter_id + '/data';
return msg;

// InfluxDB Line Protocol format (for HTTP write or Telegraf)
// measurement,tag=value field=value timestamp
const d = msg.payload;
const ts = d.ts * 1000000000; // nanoseconds

const line = [
    `energy,meter_id=${d.meter_id},location=${d.location}`,
    ` kW=${d.kW},kWh=${d.kWh},PF=${d.PF},Hz=${d.Hz}`,
    `,V_L1=${d.V_L1},V_L2=${d.V_L2},V_L3=${d.V_L3}`,
    `,I_L1=${d.I_L1},I_L2=${d.I_L2},I_L3=${d.I_L3}`,
    `,CO2_kg=${d.CO2_kg},alarm_peak=${d.alarm_peak}`,
    ` ${ts}`
].join('');

msg.payload = line;
msg.headers = { 'Content-Type': 'text/plain; charset=utf-8' };
msg.url     = 'http://localhost:8086/api/v2/write?org=wattiq&bucket=energy&precision=ns';
return msg;

node.warn('Modbus error: ' + JSON.stringify(msg.payload));
node.status({ fill: 'red', shape: 'ring', text: 'Comm error ' + new Date().toLocaleTimeString() });

// Publish offline status to MQTT
msg.payload = JSON.stringify({ status: 'error', ts: Date.now(), msg: 'Modbus comm failed' });
msg.topic = 'factory/building-a/meter01/status';
return msg;
